/**
 * Centralized API configuration for KEEP-Up
 * 
 * All API modules import from here — single source of truth.
 * At build time, REACT_APP_API_URL is baked in from .env.
 * Fallback: same-host port 3002 (for local dev only).
 */

export const API_URL: string = (() => {
  // 1. Env var set at build time (production path)
  //    Empty string = same-origin (nginx proxies /api/ to Node)
  if (typeof process.env.REACT_APP_API_URL === 'string') return process.env.REACT_APP_API_URL;

  // 2. Local development without nginx proxy: same host, API port
  if (typeof window !== 'undefined') {
    const apiPort = process.env.REACT_APP_API_PORT || '3002';
    return `${window.location.protocol}//${window.location.hostname}:${apiPort}`;
  }

  // 3. SSR / test fallback
  return 'http://localhost:3002';
})();

export default API_URL;
